{
    DEBUG("offset:%X, len:%d", offset, wlen);

    FSHC_CACHE_DISABLE();
    fshc_read(intFLASH_BASE + offset, buff, wlen, FSH_CMD_RD); // FSH_CMD_DLRD, if need
    FSHC_CACHE_RESTORE();
}

